INSERT INTO faq (
      faq_no
    , faq_ctgry_cd
    , faq_qstn_cn
    , faq_ans_cn
    , faq_sort_sn
    , faq_hit
    , faq_use_yn
    , faq_admin_id
    , faq_regist_dt
) VALUES (
      #{faqNo}
    , #{faqCtgryCd}
    , #{faqQstnCn}
    , #{faqAnsCn}
    , #{faqSortSn}
    , 0
    , #{faqUseYn}
    , #{faqAdminId}
    , SYSDATE
)

INSERT INTO faq_auth ( fa_no , fa_faq_no , fa_target_role_cd ) SELECT seq_faq_auth.NEXTVAL , #{faqNo} , T.role_cd FROM (
SELECT #{roleCd} AS ROLE_CD FROM dual
) T

